package dev.codedefense.application;
import static org.junit.jupiter.api.Assertions.*;import dev.codedefense.change.*;import dev.codedefense.domain.*;import dev.codedefense.passport.*;import java.io.*;import java.nio.file.*;import java.util.*;import java.util.concurrent.atomic.AtomicInteger;import org.junit.jupiter.api.*;import org.junit.jupiter.api.io.TempDir;
class RetryChangeDefenseUseCaseTest {@TempDir Path directory;
 @Test void expiredIdentityStopsBeforeRuntimeRunner(){PassportReceipt receipt=PassportReceipt.from(PassportTestFixtures.passport(PassportStatus.CURRENT),"11111111-1111-4111-8111-111111111111");StoredChangePassport stored=new StoredChangePassport(directory.resolve("a.md"),directory.resolve("a.json"),receipt);ChangePassportStore store=fakeStore(stored);GitChangeSource source=new GitChangeSource(){public CapturedGitChange capture(Path p,ChangeSelector s){throw new AssertionError();}public GitChangeIdentity captureIdentity(Path p,ChangeSelector s){return new GitChangeIdentity(ChangeKind.STAGED,receipt.baseCommit(),receipt.sourceIdentity(),"f".repeat(64));}};AtomicInteger calls=new AtomicInteger();GitChangeDefenseRunner runner=(p,s,d,y,o,e)->{calls.incrementAndGet();return 0;};ByteArrayOutputStream error=new ByteArrayOutputStream();int code=new RetryChangeDefenseUseCase(store,source,runner).retry(receipt.attemptId().value(),directory,true,false,new PrintWriter(System.out),new PrintWriter(error,true));assertEquals(dev.codedefense.cli.ExitCodes.GIT_EXECUTION_FAILED,code);assertEquals(0,calls.get());assertTrue(error.toString().contains("expired"));}
 private ChangePassportStore fakeStore(StoredChangePassport value){return new ChangePassportStore(){public Path save(ChangePassport p){throw new AssertionError();}public Optional<StoredPassportIdentity> readLatestIdentity(){return Optional.empty();}public List<StoredChangePassport> list(int limit){return List.of(value);}};}
}
